import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { VexClient } from '@vex_dev/sdk';

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  guardrails: {
    inputValidation: true,
    outputValidation: true,
    piiDetection: true,
    promptInjectionDetection: true,
  },
});

// app/api/chat/route.ts
export async function POST(req: Request) {
  const { messages } = await req.json();

  const result = await vex.wrapGenerateText(
    generateText,
    {
      model: openai('gpt-4o'),
      system: 'You are a helpful customer support assistant.',
      messages,
      tools: {
        searchOrders: {
          description: 'Search for customer orders by ID',
          parameters: z.object({ orderId: z.string() }),
          execute: async ({ orderId }) => {
            return await fetchOrderFromDB(orderId);
          },
        },
      },
      maxSteps: 5,
    },
    {
      traceId: crypto.randomUUID(),
      userId: req.headers.get('x-user-id') ?? undefined,
      tags: ['customer-support', 'production'],
    }
  );

  return Response.json({ text: result.text });
}

import { streamText } from 'ai';
import { anthropic } from '@ai-sdk/anthropic';
import { VexClient } from '@vex_dev/sdk';
import { z } from 'zod';

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
  streaming: {
    chunkValidationInterval: 50, // validate every 50 tokens
    haltOnViolation: true,
    violationFallbackMessage: 'I cannot continue this response. Please rephrase your request.',
  },
});

// app/api/stream/route.ts
export const runtime = 'edge';

export async function POST(req: Request) {
  const { messages } = await req.json();

  const result = await vex.wrapStreamText(
    streamText,
    {
      model: anthropic('claude-3-5-sonnet-20241022'),
      system: 'You are a financial advisor. Never provide specific investment advice.',
      messages,
      onChunk: ({ chunk }) => {
        // Vex intercepts here for real-time validation
        if (chunk.type === 'text-delta') {
          console.log('chunk:', chunk.textDelta);
        }
      },
    },
    {
      traceId: req.headers.get('x-request-id') ?? crypto.randomUUID(),
      guardrailOverrides: {
        topicRestrictions: ['specific stock recommendations', 'guaranteed returns'],
      },
    }
  );

  return result.toDataStreamResponse();
}

import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { VexClient, vexTool } from '@vex_dev/sdk';
import { z } from 'zod';

const vex = new VexClient({
  apiKey: process.env.VEX_API_KEY!,
});

// Define tools with Vex result validation schemas
const tools = {
  getProductInfo: vexTool({
    description: 'Retrieve product information by SKU',
    parameters: z.object({
      sku: z.string().regex(/^[A-Z]{2}-\d{6}$/, 'Invalid SKU format'),
    }),
    resultSchema: z.object({
      name: z.string().min(1),
      price: z.number().positive(),
      inStock: z.boolean(),
      description: z.string(),
    }),
    execute: async ({ sku }) => {
      const product = await fetchProductBySku(sku);
      return product; // Vex validates this against resultSchema before returning to model
    },
    onValidationFailure: async (error, rawResult) => {
      // Log to Vex and return a safe fallback
      await vex.logToolFailure({
        tool: 'getProductInfo',
        error: error.message,
        rawResult,
      });
      return { error: 'Product data temporarily unavailable', inStock: false };
    },
  }),
};

export async function POST(req: Request) {
  const { query } = await req.json();

  const { text, steps } = await vex.wrapGenerateText(
    generateText,
    {
      model: openai('gpt-4o'),
      prompt: query,
      tools,
      maxSteps: 3,
    },
    {
      traceId: crypto.randomUUID(),
      stepTimeoutMs: 8000, // Vex enforces per-step timeout to prevent Edge Function exhaustion
    }
  );

  return Response.json({ text, stepCount: steps.length });
}
